const input = $json;

// Tenta pegar dados de vários nodes
let dadosLoop = {};
let dadosWebhook = {};
let pegaContato = {};

try {
  dadosLoop = $('Loop Over Items').item.json || {};
} catch (e) {}

try {
  dadosWebhook = $('Webhook WGP').first().json.body || {};
} catch (e) {}

try {
  pegaContato = $('Pega Contato').item.json || {};
} catch (e) {}

// Dados do webhook Meta, se existir
const value = dadosWebhook.entry?.[0]?.changes?.[0]?.value || {};
const metadata = value.metadata || {};
const contatoMeta = value.contacts?.[0] || {};

const phoneNumberId = String(metadata.phone_number_id || '');
const wabaId = String(dadosWebhook.entry?.[0]?.id || '');

// Mapeie seus phone_number_id da Meta para inbox_id do Chatwoot
const inboxMap = {
  "1251310668056807": 25
};

// Define inbox desejado
const inboxIdDesejado = Number(
  dadosLoop.inbox_id ||
  pegaContato.inbox_id ||
  pegaContato.contact?.inbox_id ||
  inboxMap[phoneNumberId] ||
  0
);

// Fallback do source_id do contato
const sourceIdContato =
  pegaContato.contact?.source_id ||
  pegaContato.source_id ||
  null;

// Telefone
const telefone = String(
  dadosLoop.Whatsapp ||
  dadosLoop.whatsapp ||
  contatoMeta.wa_id ||
  pegaContato.Whatsapp ||
  pegaContato.contact?.phone_number ||
  ''
).replace(/\D/g, '');

// Tenta achar payload/conversas em formatos diferentes
const conversations =
  Array.isArray(input.payload) ? input.payload :
  Array.isArray(input.body?.payload) ? input.body.payload :
  Array.isArray(input.data?.payload) ? input.data.payload :
  Array.isArray(input[0]?.payload) ? input[0].payload :
  Array.isArray(input) ? input :
  [];

const getTimestamp = (conv) => {
  const value =
    conv?.last_activity_at ||
    conv?.updated_at ||
    conv?.created_at ||
    0;

  if (typeof value === 'number') return value;

  const parsed = Date.parse(value);
  return Number.isNaN(parsed) ? 0 : Math.floor(parsed / 1000);
};

const ordenarMaisRecente = (lista) => {
  return [...lista].sort((a, b) => getTimestamp(b) - getTimestamp(a));
};

const pertenceAoTelefone = (conv) => {
  if (!telefone) return true;

  const contactPhone = String(conv?.contact?.phone_number || '').replace(/\D/g, '');
  const contactIdentifier = String(conv?.contact?.identifier || '').replace(/\D/g, '');
  const metaSenderPhone = String(conv?.meta?.sender?.phone_number || '').replace(/\D/g, '');
  const metaSenderIdentifier = String(conv?.meta?.sender?.identifier || '').replace(/\D/g, '');

  return (
    contactPhone === telefone ||
    contactIdentifier === telefone ||
    metaSenderPhone === telefone ||
    metaSenderIdentifier === telefone
  );
};

const conversasInbox = conversations.filter(conv => {
  return Number(conv?.inbox_id) === inboxIdDesejado && pertenceAoTelefone(conv);
});

const conversasOpen = ordenarMaisRecente(
  conversasInbox.filter(conv => conv?.status === 'open')
);

const conversasPending = ordenarMaisRecente(
  conversasInbox.filter(conv => conv?.status === 'pending')
);

const conversasResolved = ordenarMaisRecente(
  conversasInbox.filter(conv => conv?.status === 'resolved')
);

const conversasOutras = ordenarMaisRecente(
  conversasInbox.filter(conv =>
    !['open', 'pending', 'resolved'].includes(conv?.status)
  )
);

const conversaSelecionada =
  conversasOpen[0] ||
  conversasPending[0] ||
  conversasResolved[0] ||
  conversasOutras[0] ||
  null;

// Busca source_id em vários caminhos possíveis
const sourceId =
  conversaSelecionada?.contact_inbox?.source_id ||
  conversaSelecionada?.contact?.contact_inboxes?.find(ci =>
    Number(ci?.inbox?.id) === inboxIdDesejado
  )?.source_id ||
  conversaSelecionada?.messages?.[0]?.conversation?.contact_inbox?.source_id ||
  conversaSelecionada?.last_non_activity_message?.conversation?.contact_inbox?.source_id ||
  conversaSelecionada?.last_non_activity_message?.source_id ||
  sourceIdContato ||
  null;

return [
  {
    json: {
      tem_conversa_inbox: !!conversaSelecionada,
      conversation_id: conversaSelecionada?.id || null,
      conversation_status: conversaSelecionada?.status || null,
      can_reply: conversaSelecionada?.can_reply ?? false,

      inbox_id: conversaSelecionada?.inbox_id || inboxIdDesejado || null,
      inbox_id_desejado: inboxIdDesejado || null,

      source_id: sourceId,

      precisa_criar_conversa: !conversaSelecionada,

      criterio_selecao: conversaSelecionada
        ? `conversa_${conversaSelecionada.status || 'sem_status'}_mais_recente`
        : 'nenhuma_conversa_encontrada',

      total_conversas: conversations.length,
      total_conversas_inbox: conversasInbox.length,
      total_open: conversasOpen.length,
      total_pending: conversasPending.length,
      total_resolved: conversasResolved.length,
      total_outras: conversasOutras.length,

      telefone,
      phone_number_id: phoneNumberId || null,
      WABA_ID: wabaId || dadosLoop.WABA_ID || null,

      conversa: conversaSelecionada || null
    }
  }
];

const dados = $('Webhook WGP').first().json.body;

const value = dados.entry?.[0]?.changes?.[0]?.value || {};
const contatoMeta = value.contacts?.[0] || {};
const metadata = value.metadata || {};

const telefone = String(contatoMeta.wa_id || '').replace(/\D/g, '');
const fullName = contatoMeta.profile?.name || null;
const firstName = fullName ? fullName.split(' ')[0] : null;

const phoneNumberId = String(metadata.phone_number_id || '');
const wabaId = String(dados.entry?.[0]?.id || '');

// Mapeie aqui seus números Meta para inbox_id do Chatwoot
const inboxMap = {
  "1251310668056807": 25
};

const inboxIdDesejado = Number(inboxMap[phoneNumberId] || 0);

const payload =
  Array.isArray($json.payload) ? $json.payload :
  Array.isArray($json.body?.payload) ? $json.body.payload :
  Array.isArray($json.data?.payload) ? $json.data.payload :
  Array.isArray($json[0]?.payload) ? $json[0].payload :
  [];

const contato = payload.find(contact => {
  const identifier = String(contact.identifier || '');
  const identifierLimpo = identifier.replace(/\D/g, '');
  const phoneNumber = String(contact.phone_number || '').replace(/\D/g, '');

  return (
    identifier === `${telefone}@s.whatsapp.net` ||
    identifierLimpo === telefone ||
    phoneNumber === telefone
  );
});

const contactInboxes = Array.isArray(contato?.contact_inboxes)
  ? contato.contact_inboxes
  : [];

const contactInbox = contactInboxes.find(ci =>
  Number(ci?.inbox?.id) === inboxIdDesejado
);

return [
  {
    json: {
      found: !!contato,
      has_correct_inbox: !!contactInbox,
      should_create: !contato || !contactInbox,

      first_name: firstName,
      full_name: fullName,
      Whatsapp: telefone,
      account_id: 5,
      inbox_id: inboxIdDesejado,
      WABA_ID: wabaId,
      phone_number_id: phoneNumberId,

      contact: {
        id: contato?.id || null,
        name: contato?.name || null,
        phone_number: contato?.phone_number || null,
        identifier: contato?.identifier || null,
        source_id: contactInbox?.source_id || null,
        inbox_id: contactInbox?.inbox?.id || null,
        inbox_name: contactInbox?.inbox?.name || null,
        channel_type: contactInbox?.inbox?.channel_type || null,
        provider: contactInbox?.inbox?.provider || null
      }
    }
  }
];

const webhook = $('Webhook WGP').first().json;
const body = webhook.body || {};

