const buttonText =
  message.button?.text ||
  message.button?.payload ||
  '';

const content = String(buttonText || '').trim();
const contentLower = content.toLowerCase();

const phoneNumberId = String(metadata.phone_number_id || '');
const displayPhoneNumber = String(metadata.display_phone_number || '');
const wabaId = String(body.entry?.[0]?.id || '');

const telefone = String(
  message.from ||
  contactMeta.wa_id ||
  ''
).replace(/\D/g, '');

const fullName = contactMeta.profile?.name || null;
const firstName = fullName ? fullName.split(' ')[0] : null;

const inboxMap = {
  "1251310668056807": {
    inbox_id: 25,
    inbox_name: "Wilda Gomes Clínica de Podologia WhatsApp",
    account_id: 5
  }
};

const inboxConfig = inboxMap[phoneNumberId] || {};

const inboxId =
  pegaConversa.inbox_id ||
  inboxConfig.inbox_id ||
  null;

const inboxName =
  pegaConversa.inbox_name ||
  pegaConversa.conversa?.inbox?.name ||
  inboxConfig.inbox_name ||
  null;

const accountId =
  pegaConversa.conversa?.account_id ||
  pegaConversa.account_id ||
  inboxConfig.account_id ||
  null;

const botoesOptout = [
  'Bloquear contato / Sem interesse',
  'Não receber',
  'Sem interesse',
  'Parar envios',
  'Cancelar envios',
  'Parar mensagens',
  'Cancelar mensagens',
  'Bloquear contato',
  'Cancelar'
];

const botoesOptin = [
  'Ver detalhes',
  'Conversar no WhatsApp',
  'Confirmar',
  'Responder',
  'Conversar com a empresa',
  'Conversar com a equipe',
  'Confirmar recebimento',
  'Agendar',
  'Reagendar'
];

const normalizar = (texto) =>
  String(texto || '').trim().toLowerCase();

const botoesOptoutLower = botoesOptout.map(normalizar);
const botoesOptinLower = botoesOptin.map(normalizar);
const botoesConhecidosLower = [
  ...botoesOptoutLower,
  ...botoesOptinLower
];

const isRespostaBotao =
  message.type === 'button' &&
  botoesConhecidosLower.includes(contentLower);

let botaoAcao = null;

if (isRespostaBotao && botoesOptoutLower.includes(contentLower)) {
  botaoAcao = 'optout';
}

if (isRespostaBotao && botoesOptinLower.includes(contentLower)) {
  botaoAcao = 'optin';
}

const isOptin = botaoAcao === 'optin';
const isOptout = botaoAcao === 'optout';

const sourceId =
  pegaConversa.source_id ||
  pegaConversa.conversa?.messages?.[0]?.conversation?.contact_inbox?.source_id ||
  pegaConversa.conversa?.last_non_activity_message?.conversation?.contact_inbox?.source_id ||
  telefone ||
  null;

const contactId =
  pegaConversa.conversa?.meta?.sender?.id ||
  pegaConversa.contact_id ||
  null;

const mensagens = pegaConversa.conversa?.messages || [];

const mensagensCliente = mensagens.filter(
  m => m.sender_type === 'Contact'
);

const primeiraMensagemAposEnvio =
  mensagensCliente.length === 1;

const primeiraMensagem = mensagensCliente[0];

let conteudoPrimeiraMensagem = null;

if (primeiraMensagemAposEnvio && primeiraMensagem) {

  conteudoPrimeiraMensagem =
    primeiraMensagem.content ||
    (
      primeiraMensagem.attachments?.length
        ? `[${primeiraMensagem.attachments[0].file_type}]`
        : null
    );

}

return [
  {
    json: {
      conversation_id: pegaConversa.conversation_id || pegaConversa.conversa?.id || null,
      contact_id: contactId,
      account_id: accountId,

      inbox_id: inboxId,
      inbox_name: inboxName,

      source_id: sourceId,

      sender_name: fullName,
      sender_first_name: firstName,
      sender_phone: telefone,
      sender_identifier: telefone ? `${telefone}@s.whatsapp.net` : null,

      message_id: message.id || null,
      message_type: message.type || null,
      content_type: message.type || null,
      message_created_at: message.timestamp ? Number(message.timestamp) : null,
      message_content: content,
      message_content_lower: contentLower,

      button_payload: message.button?.payload || null,
      button_text: message.button?.text || null,

      is_resposta_botao: isRespostaBotao,
      botao_texto: isRespostaBotao ? content : null,
      botao_texto_lower: isRespostaBotao ? contentLower : null,
      botao_tipo: isRespostaBotao ? 'whatsapp_button_reply' : null,

      botao_acao: botaoAcao,
      is_optin: isOptin,
      is_optout: isOptout,

      is_reply_to_wamid: String(message.context?.id || '').startsWith('wamid.'),
      in_reply_to_external_id: message.context?.id || null,
      in_reply_to_from: message.context?.from || null,

      conversation_status: pegaConversa.conversation_status || pegaConversa.conversa?.status || null,
      conversation_can_reply: pegaConversa.can_reply ?? pegaConversa.conversa?.can_reply ?? null,
      conversation_labels: pegaConversa.conversa?.labels || [],
      unread_count: pegaConversa.conversa?.unread_count || 0,

      phone_number_id: phoneNumberId,
      display_phone_number: displayPhoneNumber,
      WABA_ID: wabaId,

      precisa_criar_conversa: pegaConversa.precisa_criar_conversa ?? null,
      tem_conversa_inbox: pegaConversa.tem_conversa_inbox ?? null,
      primeira_mensagem_apos_envio: primeiraMensagemAposEnvio,
      conteudo_primeira_mensagem: conteudoPrimeiraMensagem
    }
  }
];

const conversas = $input.all()
  .map(i => i.json)
  .filter(c => Number(c.inbox_id) === 25);

return conversas.map(conversa => {

  const primeiraMensagem = (conversa.messages || [])
    .filter(m =>
      m.sender_type === 'Contact' &&
      !m.private
    )
    .sort((a, b) => a.created_at - b.created_at)[0];

  return {
    json: {
      conversation_id: conversa.id,
      nome: conversa.meta?.sender?.name,
      telefone: conversa.meta?.sender?.phone_number,
      primeira_mensagem: primeiraMensagem?.content || null,
      primeira_mensagem_created_at: primeiraMensagem?.created_at || null
    }
  };

});

return $input.all().map(item => {

  const conversa = item.json;

  const primeiraMensagem = (conversa.payload || [])
    .filter(m =>
      m.message_type === 0 &&
      !m.private &&
      m.sender?.type === 'contact'
    )
    .sort((a, b) => a.created_at - b.created_at)[0];

  let conteudo = primeiraMensagem?.content;

  if (!conteudo && primeiraMensagem?.attachments?.length) {
    conteudo = `[${primeiraMensagem.attachments[0].file_type}]`;
  }

  return {
    json: {
      conversation_id: primeiraMensagem?.conversation_id,
      nome: conversa.meta?.contact?.name,
      telefone: conversa.meta?.contact?.phone_number,
      primeira_mensagem: conteudo,
      primeira_mensagem_created_at: primeiraMensagem?.created_at
    }
  };

});
